// Sanity checks against the auto-generated .d.ts. Loads the file the
// fixture-lib build emits to zig-out/lib and verifies that:
//   - representative function/class/namespace/constant shapes are present
//   - snake_case → camelCase happened consistently
//   - enum tag unions use the camelCase form
// Catches accidental drift in the dts.zig emitter.

import { describe, expect, test } from "bun:test";
import { readFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { loadFixture } from "../helpers/addon";

// trigger the build so the .d.ts is fresh
loadFixture();

const here = dirname(fileURLToPath(import.meta.url));
const dtsPath = join(here, "..", "fixture-lib", "zig-out", "lib", "fixture.d.ts");
const dts = readFileSync(dtsPath, "utf-8");

describe("auto-generated .d.ts — header", () => {
  test("starts with the do-not-edit banner", () => {
    expect(dts.startsWith("// auto-generated by napi-zig. do not edit.")).toBe(true);
  });
});

describe("primitive function signatures", () => {
  test("i32 round-trip uses number", () => {
    expect(dts).toContain("export function roundtripI32(a0: number): number;");
  });

  test("i64 round-trip uses bigint both ways", () => {
    expect(dts).toContain("export function roundtripI64(a0: bigint): bigint;");
  });

  test("optional ?i32 becomes optional param + nullable return", () => {
    expect(dts).toContain(
      "export function roundtripOptionalI32(a0?: number | null): number | null;",
    );
  });

  test("void return type", () => {
    expect(dts).toContain("export function returnsVoid(): void;");
  });
});

describe("constants", () => {
  test("typed export const for booleans, numbers, strings", () => {
    expect(dts).toContain("export const boolTrue: boolean;");
    expect(dts).toContain("export const i32Value: number;");
    expect(dts).toContain("export const stringValue: string;");
  });

  test("snake_case constant emitted as camelCase", () => {
    expect(dts).toContain("export const snakeCaseName: number;");
    expect(dts).not.toContain("snake_case_name");
  });

  test("comptime_int / comptime_float become number", () => {
    expect(dts).toContain("export const comptimeIntValue: number;");
    expect(dts).toContain("export const comptimeFloatValue: number;");
  });
});

describe("structs", () => {
  test("inline object type with snake→camel field renaming", () => {
    expect(dts).toContain(
      "export function formatOptions(a0: { filePath: string; lineCount: number; verbose?: boolean }): string;",
    );
  });

  test("optional ?T field is rendered with `?:` and nullable union", () => {
    expect(dts).toContain("nickName?: string | null");
  });

  test("nested struct is inlined", () => {
    expect(dts).toContain("point: { x: number; y: number }");
  });
});

describe("enums", () => {
  test("tag union uses the camelCase form", () => {
    expect(dts).toMatch(/"debug"\s*\|\s*"info"\s*\|\s*"warning"\s*\|\s*"errorLevel"/);
    expect(dts).not.toContain('"error_level"');
  });
});

describe("namespaces", () => {
  test("export namespace block for `math`", () => {
    expect(dts).toContain("export namespace math {");
  });

  test("nested namespaces are present", () => {
    expect(dts).toMatch(/namespace inner \{[\s\S]+function deep/);
    expect(dts).toMatch(/namespace deeper \{[\s\S]+function deepest/);
  });

  test("snake_case namespace exposed as camelCase", () => {
    expect(dts).toContain("export namespace constantsNs {");
    expect(dts).not.toContain("constants_ns");
  });
});

describe("classes", () => {
  test("Counter class with constructor, methods, snake→camel", () => {
    expect(dts).toContain("export class Counter {");
    expect(dts).toContain("constructor(a0: number);");
    expect(dts).toContain("increment(): number;");
    expect(dts).toContain("addN(a0: number): number;");
    expect(dts).toContain("get(): number;");
    expect(dts).toContain("reset(): void;");
  });

  test("Greeter constructor params start at a0 (Env is dropped)", () => {
    expect(dts).toContain("export class Greeter {");
    expect(dts).toContain("constructor(a0: string);");
    expect(dts).toContain("greet(): string;");
  });
});

describe("Val / Callback escape hatches", () => {
  test("Val parameter / return becomes unknown", () => {
    expect(dts).toContain("a0: unknown[]"); // forEach takes []napi.Val
  });

  test("Callback becomes a function type", () => {
    expect(dts).toContain("(...args: unknown[]) => unknown");
  });

  test("raw mode (Env, CallInfo) emits ...unknown[] → unknown", () => {
    expect(dts).toContain("export function variadicSum(...args: unknown[]): unknown;");
  });
});
